body:
Hello.

I'm getting another bug while trying to run Yosys GLS. Interestingly, this example works with my Verilator build from February (a69cb9b0), but it looks like it was broken in March. Possibly #4937 is to blame?

This is a minimum example:

```
Ubuntu 22.04.4 LTS
Verilator 5.025 devel rev v5.024-56-g5f85c8942
```
Test case:
```systemverilog
module A (
  output [2:0] Y
);
endmodule

module B;
  wire [2:0] w1;
  wire w2;
  A A (
    .Y({ w1[2], w1[0], w2 })
  );
  assign w1[1] = w1[2];
endmodule
```
```bash
verilator --lint-only test.v
```
Output:
```
%Error: Internal Error: test.v:26:15: ../V3DfgDfgToAst.cpp:144: Intermediate DFG value with multiple uses
   26 |     .Y({ w1[2], w1[0], w2 })
      |               ^
```

<details>
<summary>Here is a slightly fuller example</summary>
<br>

```systemverilog
// https://github.com/YosysHQ/yosys/blob/17903703/techlibs/common/simlib.v#L882-L902
module \$mul (A, B, Y);

parameter A_SIGNED = 0;
parameter B_SIGNED = 0;
parameter A_WIDTH = 0;
parameter B_WIDTH = 0;
parameter Y_WIDTH = 0;

input [A_WIDTH-1:0] A;
input [B_WIDTH-1:0] B;
output [Y_WIDTH-1:0] Y;

generate
	if (A_SIGNED && B_SIGNED) begin:BLOCK1
		assign Y = $signed(A) * $signed(B);
	end else begin:BLOCK2
		assign Y = A * B;
	end
endgenerate

endmodule

module B;
  wire [15:0] _0_;
  wire [15:0] _4_;
  \$mul  #(
    .A_SIGNED(32'd1),
    .A_WIDTH(32'd8),
    .B_SIGNED(32'd1),
    .B_WIDTH(32'd8),
    .Y_WIDTH(32'd16)
  ) _7_ (
    .A(a_i),
    .B(b_i),
    .Y({ _0_[15], _0_[11:0], _4_[2:0] })
  );
  assign _0_[14:12] = { _0_[15], _0_[15], _0_[15] };
  assign _4_[15:3] = { _0_[15], _0_[11:0] };
endmodule
```

</details>
